DECLARE PARAMETER country TYPE TEXT (
    default_value = 'DE'
);
LOAD weather_csv FROM http (
    url = format('https://cdn.dashql.com/demo/weather/{}', global.country)
);

DECLARE PARAMETER country TYPE TEXT (
    default_value = 'DE'
);
LOAD weather_csv FROM http (
    url = format('https://cdn.dashql.com/demo/weather/{}', global.country)
);

CREATE VIEW foo AS
    SELECT a1::INTEGER AS a
    FROM generate_series(0, 1000000) AS a(a1);

VIZ foo USING TABLE;

CREATE VIEW foo AS
    SELECT a1::INTEGER AS a
    FROM generate_series(0, 1000000) AS a(a1);

VIZ foo USING TABLE (
    pos = (r = 5, c = 1, w = 8, h = 4)
);
